export type Carrier = 'SKT' | 'KT' | 'LGU+';

export interface PlanCombination {
  id: string;
  carrier: Carrier;
  lines: number; // 회선 수 (1~5)
  mobilePlan: string; // 모바일 요금제
  mobileSpeed: string; // 모바일 속도/데이터
  mobilePrice?: number; // 모바일 금액/할인금액
  internetPlan: string; // 인터넷 요금제 이름
  internetSpeed: string; // 인터넷 속도 (100Mbps, 500Mbps, 1Gbps 등)
  tvPlan: string; // TV 요금제
  internetTvPrice?: number; // 인터넷+TV 결합금액
  totalPrice: number; // 총 납부액(원)
  discountType?: string; // 결합 상품명 (선택)
}

