/**
* 
* 통신사와 회선 수를 기반으로 해당하는 모든 요금제 조합 목록을 반환합니다.
*/
export const getPlanCombinations = (carrier: Carrier, lines: number): PlanCombination[] => {
  return MOCK_PLAN_COMBINATIONS.filter(
    (item) => item.carrier === carrier && item.lines === lines
  ).map((item) => {
    const formattedMobilePlan = item.mobilePrice !== undefined && !item.mobilePlan.includes("원")
      ? `${item.mobilePlan} (${item.mobilePrice.toLocaleString("ko-KR")}원)`
      : item.mobilePlan;
    const formattedTvPlan = item.internetTvPrice !== undefined && !item.tvPlan.includes("원")
      ? `${item.tvPlan} (인터넷+TV 결합: ${item.internetTvPrice.toLocaleString("ko-KR")}원)`
      : item.tvPlan;

    return {
      ...item,
      mobilePlan: formattedMobilePlan,
      tvPlan: formattedTvPlan,
    };
  });
};
